#!/usr/bin/env python3
from pathlib import Path
import json, re, shutil, html, datetime
ROOT=Path.cwd(); PUBLIC=ROOT/'public'; RESTORE=ROOT/'restore'/'public'; ASSETS=PUBLIC/'assets'; REPORTS=ROOT/'reports'; CONTENT=ROOT/'content'/'goalos'; EVIDENCE=ROOT/'evidence'/'demo'; DOCS=ROOT/'docs'/'website'; REVIEWER=ROOT/'docs'/'reviewer'; ISSUE=ROOT/'issue-bodies'; TEMPLATES=ROOT/'.github'/'ISSUE_TEMPLATE'
VERSION='v0.35.0-site-experience-command-center-v13'
BOUNDARY='No user data. No user funds. No wallet. No transaction. No network call. No production authority. Human review required.'
TOKEN_BOUNDARY='$AGIALPHA public contract address only. Not available from us. No sale. No custody. No wallet support. No investment, trading, legal, tax, exchange, bridge, liquidity, or regulatory advice.'
CORE_PAGES={'index.html','site-map.html','pathfinder.html','demo-ecosystem-registry.html','website-operating-system.html','site-health.html','search.html','trust-boundary.html','token-boundary.html','docs.html','404.html'}

def ensure_dirs():
    for p in [PUBLIC,ASSETS,REPORTS,CONTENT,EVIDENCE,DOCS,REVIEWER,ISSUE,TEMPLATES,ROOT/'.goalos'/'packs']:
        p.mkdir(parents=True,exist_ok=True)

def copy_missing_public():
    restored=[]
    if RESTORE.exists():
        for src in RESTORE.rglob('*'):
            if src.is_dir(): continue
            rel=src.relative_to(RESTORE); dest=PUBLIC/rel
            if not dest.exists():
                dest.parent.mkdir(parents=True,exist_ok=True); shutil.copy2(src,dest); restored.append(str(rel))
    return restored

def read_text(path):
    try: return path.read_text(encoding='utf-8', errors='ignore')
    except Exception: return ''

def strip_tags(s): return re.sub(r'\s+',' ',re.sub(r'<[^>]+>',' ',s or '')).strip()

def title_for(path):
    txt=read_text(path)
    for pat in [r'<title[^>]*>(.*?)</title>',r'<h1[^>]*>(.*?)</h1>']:
        m=re.search(pat,txt,re.I|re.S)
        if m and strip_tags(m.group(1)): return strip_tags(m.group(1))[:140]
    return path.stem.replace('-',' ').replace('_',' ').title()

def desc_for(path):
    txt=strip_tags(read_text(path)).replace('Skip to content','').strip()
    return (txt[:260].rsplit(' ',1)[0]+'…') if len(txt)>260 else (txt or title_for(path))

def category_for(path,title,desc):
    s=(path.name+' '+title+' '+desc[:1000]).lower()
    if any(k in s for k in ['loop-to-rsi','from loop to rsi','rsi','sovereign invention']): return 'Loop → RSI'
    if any(k in s for k in ['loop contract','loop flight','bottleneck','loop-']): return 'Loop Demos'
    if any(k in s for k in ['proof run','evidence docket','reviewer','replay','proof ledger','docket','validator']): return 'Evidence & Review'
    if any(k in s for k in ['mission','forge','work os','action','trace contract']): return 'Mission & Work OS'
    if any(k in s for k in ['token','privacy','trust','data-boundary','no-data','terms','responsible','legal','boundary']): return 'Trust & Boundary'
    if any(k in s for k in ['start','pathfinder','site map','registry','docs','faq','glossary','help','search','run locally','troubleshooting']): return 'Navigation & Docs'
    if any(k in s for k in ['capability','settlement','value','economy','agialpha','node','jobs']): return 'Capability & Economy'
    return 'Additional / Preserved'

def role_for(cat,path):
    if cat=='Loop → RSI': return 'RSI governance console'
    if cat=='Loop Demos': return 'loop instrumentation demo'
    if cat=='Evidence & Review': return 'reviewer / evidence route'
    if cat=='Mission & Work OS': return 'mission orchestration surface'
    if cat=='Trust & Boundary': return 'trust and boundary surface'
    if cat=='Navigation & Docs': return 'navigation / documentation'
    if cat=='Capability & Economy': return 'capability / value route'
    return 'interactive demo' if any(k in path.name for k in ['demo','lab','console']) else 'public page'

def specifics(cat):
    if cat=='Loop → RSI': return ('Public-safe objective, RSI scenario, OMNI/search pressure, Move-37 stress, council review toggle.','RSI state, ECI ledger, baseline report, Move-37 dossier, council memo, reviewer brief.','Schema-bound artifacts, state hash, drift sentinel, executed evidence, baseline comparison, risk gate, OMNI allocation-only, replay, council, human boundary.','RSI_REVIEW_READY / MOVE37_DOSSIER_REVIEW_READY / REJECT_OMNI_OUTCOME_AUTHORITY / BLOCK_PRIVACY_BOUNDARY')
    if cat=='Loop Demos': return ('Public-safe objective, loop scenario, role separation, disk-state toggle, restart, trace review, bottleneck stress.','Loop contract, flight recorder, trace ledger, disk-state pack, bottleneck report, reviewer brief.','Contract first, role separation, write state to disk, independent evaluator, restartability, trace reading, public/private boundary.','LOOP_REVIEW_READY / REJECT_NO_CONTRACT / HOLD_STATE_FILES_REQUIRED / BLOCK_PRIVACY_BOUNDARY')
    if cat=='Evidence & Review': return ('Claim, docket, claims matrix, proof packets, baselines, replay path, validator notes, review decision.','Evidence Docket, validator packet, reviewer brief, gate ledger, claim-boundary report.','Replay, evidence integrity, baseline comparison, cost/risk ledger, human review, claim boundary.','REVIEW_READY / HOLD_REPLAY_REQUIRED / REVISE_CLAIM / REJECT_UNSUPPORTED')
    if cat=='Mission & Work OS': return ('Objective, mission contract, constraints, risk class, allowed tools, success/failure criteria.','Mission plan, action graph, Evidence Docket plan, Chronicle entry, capability package.','Mission contract, verification, risk ledger, action scope, rollback, human review.','MISSION_REVIEW_READY / HOLD_RISK_REVIEW / HOLD_EVIDENCE_REQUIRED')
    if cat=='Trust & Boundary': return ('Boundary question, token/data/privacy/legal review context.','Boundary statement, token notice, no-data/no-funds guardrail, review instructions.','No user data, no user funds, no wallet, no transaction, no advice, no production authority.','BOUNDARY_VISIBLE / BLOCK_PRIVATE_DATA / TOKEN_BOUNDARY_ACKNOWLEDGED')
    if cat=='Capability & Economy': return ('Accepted proof, capability candidate, value realization scenario, capacity allocation policy.','Capability package, value ledger, allocation plan, settlement simulation, Chronicle pointer.','Evidence Docket, validator review, capability package, value ledger, risk boundary, human review.','CAPABILITY_REVIEW_READY / HOLD_VALUE_LEDGER / HOLD_HUMAN_REVIEW')
    return ('User intent, route search, page-specific public-safe action.','Guidance, links, public-safe artifacts where applicable.','Public-alpha boundary, route integrity, no-data/no-funds, human review.','ROUTE_READY / PRESERVED / REVIEW_IF_NEEDED')

def build_routes():
    routes=[]
    for p in sorted(PUBLIC.glob('*.html')):
        title=title_for(p); desc=desc_for(p); cat=category_for(p,title,desc); inp,out,gates,state=specifics(cat)
        routes.append({'path':p.name,'url':p.name,'title':title,'description':desc,'category':cat,'role':role_for(cat,p),'inputs':inp,'outputs':out,'gates':gates,'next_state':state})
    return routes

def esc(s): return html.escape(str(s or ''),quote=True)
def write(path,text): path.parent.mkdir(parents=True,exist_ok=True); path.write_text(text,encoding='utf-8')

def head(title): return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{esc(title)}</title><link rel="stylesheet" href="assets/goalos-site-experience-command-center-v13.css"><link rel="stylesheet" href="assets/goalos-command-palette-v13.css"></head><body class="gx13"><a class="skip" href="#main">Skip to content</a>'''

def nav(active='Start'):
    links=[('index.html','Start'),('pathfinder.html','Pathfinder'),('site-map.html','All Pages'),('demo-ecosystem-registry.html','Registry'),('proof-run-001-docket.html','Proof Run 001'),('from-loop-to-rsi-state-capacity.html','Loop→RSI'),('site-health.html','Site Health'),('trust-boundary.html','Trust'),('search.html','Search')]
    return '<header class="topbar"><a class="brand" href="index.html"><span class="mark">α</span><span><b>GOALOS</b><small>AGIALPHA ASCENSION</small></span></a><nav>'+''.join(f'<a class="{"active" if label==active else ""}" href="{href}">{label}</a>' for href,label in links)+'</nav><button class="pill" data-gx13-command>Menu /</button></header>'

def foot(): return f'''<footer class="footer"><p><b>GoalOS AGIALPHA Ascension</b> — public-alpha proof operating system. AI creates output. GoalOS creates proof.</p><p>{BOUNDARY}</p><p><a href="trust-boundary.html">Trust Boundary</a> · <a href="token-boundary.html">Token Boundary</a> · <a href="site-map.html">All Pages</a> · <a href="site-health.html">Site Health</a></p></footer><script src="assets/goalos-site-index-data-v13.js"></script><script src="assets/goalos-site-experience-command-center-v13.js"></script><script src="assets/goalos-command-palette-v13.js"></script></body></html>'''

def route_cards(routes,cat=None,limit=None):
    rs=[r for r in routes if cat is None or r['category']==cat]
    if limit: rs=rs[:limit]
    return ''.join(f'''<article class="route-card" data-category="{esc(r['category'])}" data-title="{esc(r['title']).lower()}" data-desc="{esc(r['description']).lower()}"><div class="route-top"><span class="badge">{esc(r['category'])}</span><a href="{esc(r['url'])}">Open →</a></div><h3>{esc(r['title'])}</h3><p>{esc(r['description'])}</p><small>{esc(r['role'])}</small></article>''' for r in rs)

