def inject_shell():
    for p in PUBLIC.glob('*.html'):
        if p.name in CORE_PAGES: continue
        txt=read_text(p)
        if not txt or 'goalos-command-palette-v13.js' in txt: continue
        head_inject='<link rel="stylesheet" href="assets/goalos-command-palette-v13.css"><script src="assets/goalos-site-index-data-v13.js"></script>'
        if '</head>' in txt.lower(): txt=re.sub(r'</head>',head_inject+'</head>',txt,count=1,flags=re.I)
        body_inject='<a class="gx13-open-map" href="site-map.html">Open all pages</a><script src="assets/goalos-command-palette-v13.js"></script>'
        if '</body>' in txt.lower(): txt=re.sub(r'</body>',body_inject+'</body>',txt,count=1,flags=re.I)
        else: txt+=body_inject
        write(p,txt)

def local_link_health():
    broken=[]
    for p in PUBLIC.glob('*.html'):
        for href in re.findall(r'href=["\']([^"\']+)["\']',read_text(p),re.I):
            if not href or href.startswith(('#','http://','https://','mailto:','tel:','javascript:','../')): continue
            h=href.split('#')[0].split('?')[0]
            if not h: continue
            target=(p.parent/h).resolve()
            try: target.relative_to(PUBLIC.resolve())
            except Exception: continue
            ok=(target/'index.html').exists() if h.endswith('/') else (target.exists() or target.with_suffix('.html').exists())
            if not ok: broken.append({'page':p.name,'href':h})
    return broken

